  methods: {
    async fetchStaff() {
      try {
        const res = await axios.get("/api/staff");
        this.staff = res.data.staff;
      } catch (err) {
        this.showToast("Failed to fetch staff", true);
      }
    },
    async inviteStaff() {
      try {
        await axios.post("/api/staff/invite", {
          email: this.email
        });
        this.showToast("Invitation sent!");
        this.email = "";
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error sending invite", true);
      }
    },
    async approveStaff(id, data = {}) {
      try {
        const payload = {
          joiningDate: data.joiningDate || new Date().toISOString(),
          position: data.position,
          salary: data.salary,
          phone: data.phone
        };
        const res = await axios.put(`/api/staff/approve/${id}`, payload);
        this.showToast(res.data.message || "Staff approved successfully");
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error approving staff", true);
      }
    },
    openEditModal(staff) {
      this.isApproveMode = false;
      this.editForm = {
        id: staff._id,
        position: staff.position || "",
        salary: staff.salary || "",
        phone: staff.phone || ""
      };
      this.showEditModal = true;
      this.activeMenu = null;
    },
    openApproveModal(staff) {
      this.isApproveMode = true;
      this.editForm = {
        id: staff._id,
        position: staff.position || "",
        salary: staff.salary || "",
        phone: staff.phone || "",
        joiningDate: staff.dateOfJoining ? new Date(staff.dateOfJoining).toISOString().split("T")[0] : new Date().toISOString().split("T")[0]
      };
      this.showEditModal = true;
      this.activeMenu = null;
    },
    closeEditModal() {
      this.showEditModal = false;
      this.editForm = {
        id: null,
        position: "",
        salary: "",
        phone: "",
        joiningDate: ""
      };
    },
    async submitStaffDetails() {
      if (this.isApproveMode) {
        await this.approveStaff(this.editForm.id, this.editForm);
      } else {
        await this.updateStaffDetails(this.editForm.id, this.editForm);
      }
      this.closeEditModal();
    },
    async updateStaffDetails(id, data) {
      try {
        const res = await axios.put(`/api/staff/update-details/${id}`, {
          position: data.position,
          salary: data.salary,
          phone: data.phone
        });
        this.showToast(res.data.message || "Details updated");
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error updating details", true);
      }
    },
    async approveResignation(id) {
      try {
        const res = await axios.put(`/api/staff/resign/approve/${id}`);
        this.showToast(res.data.message || "Resignation approved successfully");
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error approving resignation", true);
      }
    },
    async rejectResignation(id) {
      try {
        const res = await axios.put(`/api/staff/resign/reject/${id}`);
        this.showToast(res.data.message || "Resignation rejected");
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error rejecting resignation", true);
      }
    },
    async setStatus(id, status) {
      try {
        await axios.put(`/api/staff/status/${id}`, {
          status
        });
        this.showToast("Status updated successfully");
        this.fetchStaff();
      } catch (err) {
        this.showToast("Failed to update status", true);
      }
    },
    // --- Delete with Modal ---
    openDeleteModal(id) {
      this.deleteId = id;
      this.showDeleteModal = true;
    },
    cancelDelete() {
      this.showDeleteModal = false;
      this.deleteId = null;
    },
    async confirmDelete() {
      try {
        await axios.delete(`/api/staff/${this.deleteId}`);
        this.showToast("Staff deleted successfully");
        this.fetchStaff();
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error deleting staff", true);
      }
      this.showDeleteModal = false;
      this.deleteId = null;
    },
    toggleMenu(staffId) {
      this.activeMenu = this.activeMenu === staffId ? null : staffId;
    },
    // --- RFID ---
    openRfidModal(staff) {
      this.rfidForm = {
        id: staff._id,
        staffName: staff.name || staff.email,
        uid: staff.rfidUid || "",
        currentUid: staff.rfidUid || ""
      };
      this.rfidError = "";
      this.showRfidModal = true;
      this.activeMenu = null;
    },
    closeRfidModal() {
      this.showRfidModal = false;
      this.rfidError = "";
      this.rfidForm = {
        id: null,
        staffName: "",
        uid: "",
        currentUid: ""
      };
    },
    async submitRfid() {
      const uid = this.rfidForm.uid.trim();
      if (!/^[A-Z0-9]{3,10}$/.test(uid)) {
        this.rfidError = "UID must be 3–10 uppercase letters (A–Z) and numbers (0–9) only.";
        return;
      }
      this.rfidError = "";
      try {
        const res = await axios.put(`/api/staff/rfid/${this.rfidForm.id}`, {
          rfidUid: uid
        });
        this.showToast(res.data.message || "RFID UID assigned successfully");
        this.closeRfidModal();
        this.fetchStaff();
      } catch (err) {
        this.rfidError = err.response?.data?.message || "Error assigning RFID UID";
      }
    },
    // --- Salary ---
    openSalaryModal(staff) {
      this.currentStaff = staff;
      this.salaryMonth = new Date().toISOString().slice(0, 7); // YYYY-MM
      this.salaryData = null;
      this.showSalaryModal = true;
      this.activeMenu = null;
      this.calculateSalary();
    },
    closeSalaryModal() {
      this.showSalaryModal = false;
      this.currentStaff = null;
      this.salaryData = null;
    },
    async calculateSalary() {
      if (!this.currentStaff || !this.salaryMonth) return;
      this.salaryLoading = true;
      try {
        const res = await axios.get(`/api/salary/calculate/${this.currentStaff._id}?month=${this.salaryMonth}`);
        if (res.data.success) {
          this.isSalaryPaid = res.data.isPaid;
          this.salaryData = res.data.data;
        }
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error calculating salary", true);
      } finally {
        this.salaryLoading = false;
      }
    },
    async payNow() {
      if (!this.salaryData || !this.currentStaff) return;
      this.razorpayLoading = true;
      try {
        const res = await axios.post("/api/salary/create-order", {
          amount: this.salaryData.finalSalary,
          staffId: this.currentStaff._id,
          monthAndYear: this.salaryData.monthAndYear
        });
        if (res.data.success) {
          const options = {
            key: res.data.key,
            amount: res.data.amount,
            currency: res.data.currency,
            order_id: res.data.orderId,
            name: "Cochin Distributors",
            description: `Salary for ${this.salaryData.monthAndYear}`,
            handler: async response => {
              await this.verifySalaryPayment(response);
            },
            prefill: {
              name: this.currentStaff.name || "Staff",
              email: this.currentStaff.email || "",
              contact: this.currentStaff.phone ? this.currentStaff.phone.length === 10 ? '+91' + this.currentStaff.phone : this.currentStaff.phone : ""
            },
            theme: {
              color: "#10b981"
            }
          };
          const rzp = new window.Razorpay(options);
          rzp.open();
        }
      } catch (err) {
        this.showToast(err.response?.data?.message || "Error initiating payment", true);
      } finally {
        this.razorpayLoading = false;
      }
    },
    async verifySalaryPayment(response) {
      try {
        const res = await axios.post("/api/salary/verify-payment", {
          ...response,
          salaryData: this.salaryData
        });
        if (res.data.success) {
          this.showToast("Salary paid successfully!");
          this.isSalaryPaid = true;
          this.salaryData.paidAt = new Date();
        }
      } catch (err) {
        this.showToast("Payment verification failed", true);
      }
    },
    loadRazorpay() {
      if (!window.Razorpay) {
        const script = document.createElement("script");
        script.src = "https://checkout.razorpay.com/v1/checkout.js";
        script.async = true;
        document.body.appendChild(script);
      }
    },
    showToast(message, isError = false) {
      this.toastMessage = message;
      this.toastError = isError;
      setTimeout(() => {
        this.toastMessage = "";
        this.toastError = false;
      }, 3000);
    },
    // --- PDF Methods (unchanged) ---
    exportStaffPDF(staff) {
