      doc.setFontSize(16);
      doc.setFont("helvetica", "bold");
      doc.text("COCHIN DISTRIBUTORS", 75, 18);
      doc.setFontSize(11);
      doc.setFont("helvetica", "normal");
      doc.text("Merchant Association Building,", 82, 26);
      doc.text("Santhi Nagar, Kattappana", 87, 32);
      doc.text("Ph: 9447419293, 9446074962", 83, 38);
      doc.setDrawColor(0);
      doc.line(14, 45, 200, 45);
      autoTable(doc, {
        startY: 50,
        head: [["Name", "Email", "Phone", "Gender", "Address", "Pincode", "Position", "Joining Date", "Resign Date", "Status"]],
        body: this.staff.map(s => [s.name || "—", s.email, s.phone || "—", s.gender || "—", s.address || "—", s.pincode || "—", s.position || "—", s.dateOfJoining ? new Date(s.dateOfJoining).toLocaleDateString() : "—", s.resignationDate ? new Date(s.resignationDate).toLocaleDateString() : "—", s.status || "—"])
      });
      let footerY = doc.internal.pageSize.getHeight() - 15;
      doc.setFontSize(10);
      doc.setFont("helvetica", "italic");
      doc.text(`Generated on ${new Date().toLocaleDateString()} at ${new Date().toLocaleTimeString()}`, 14, footerY);
      doc.save("staff-report.pdf");
    }
  },
  mounted() {
    this.fetchStaff();
    this.loadRazorpay();
  }
};
